// // This module implements a 2-bit synchronous counter that counts from 11 to 00 in binary.
module counter_2bit (
    input wire clk,
    input wire reset,
    output reg [1:0] count
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 2'b00;
        end else begin
            count <= count + 1;
        end
    end
endmodule
